var maximumBeauty = function(items, queries) {
    const sorted = items.slice().sort((a, b) => a[0] - b[0]);
    const n = sorted.length;
    const prices = new Array(n);
    const prefixMax = new Array(n);
    let best = 0;
    for (let i = 0; i < n; i++) {
        best = Math.max(best, sorted[i][1]);
        prefixMax[i] = best;
        prices[i] = sorted[i][0];
    }
    function upperBound(target) {
        let lo = 0, hi = n;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (prices[mid] <= target) lo = mid + 1; else hi = mid;
        }
        return lo;
    }
    const res = [];
    for (const q of queries) {
        const idx = upperBound(q) - 1;
        res.push(idx >= 0 ? prefixMax[idx] : 0);
    }
    return res;
};
